import logging
import logging.handlers
import os
import stat
from pathlib import Path

# Create log directory with secure permissions
log_dir = Path("/var/log/application")
log_dir.mkdir(parents=True, exist_ok=True)
os.chmod(log_dir, stat.S_IRWXU | stat.S_IRGRP | stat.S_IXGRP | stat.S_IROTH | stat.S_IXOTH)

# Create secure file handler with rotation
file_handler = logging.handlers.RotatingFileHandler(
    filename=log_dir / "application.log",
    maxBytes=10485760,  # 10MB
    backupCount=5,
    encoding='utf-8'
)

# Set secure permissions on log file
os.chmod(log_dir / "application.log", stat.S_IRUSR | stat.S_IWUSR | stat.S_IRGRP | stat.S_IWGRP)

# Create formatter
formatter = logging.Formatter(
    '%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

# Apply formatter to handler
file_handler.setFormatter(formatter)

# Create logger
logger = logging.getLogger('application')
logger.setLevel(logging.INFO)

# Add handler to logger
logger.addHandler(file_handler)

# Prevent propagation to root logger
logger.propagate = False

# Secure logging configuration
logging.basicConfig(
    level=logging.INFO,
    handlers=[file_handler],
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)